<?php
namespace App\Http\Controllers;
use App\Actions\Invoices\CreateInvoice; use App\Models\{Customer,Invoice,Product}; use Illuminate\Http\RedirectResponse; use Illuminate\Http\Request; use Illuminate\View\View;
class InvoiceController extends Controller { public function index(Request $request): View { $items=Invoice::with('customer')->where('business_id',$request->user()->current_business_id)->latest()->paginate(15); return view('invoices.index', compact('items')); } public function create(Request $request): View { $customers=Customer::where('business_id',$request->user()->current_business_id)->orderBy('name')->get(); $products=Product::where('business_id',$request->user()->current_business_id)->where('active',true)->orderBy('name')->get(); return view('invoices.create', compact('customers','products')); } public function store(Request $request, CreateInvoice $createInvoice): RedirectResponse { $invoice=$createInvoice->handle($request->user(), $request->validate(['customer_id'=>'required|exists:customers,id','issue_date'=>'required|date','due_date'=>'required|date|after_or_equal:issue_date','notes'=>'nullable|string','items'=>'required|array|min:1','items.*.description'=>'required|string|max:255','items.*.quantity'=>'required|numeric|min:0.01','items.*.unit_price'=>'required|numeric|min:0','items.*.tax_rate'=>'nullable|numeric|min:0|max:100'])); return redirect()->route('invoices.show',$invoice)->with('status','Invoice created.'); } public function show(Invoice $invoice): View { $this->authorize('view',$invoice); $invoice->load('customer','items','payments'); return view('invoices.show', compact('invoice')); } public function edit(Invoice $invoice): View { $this->authorize('update',$invoice); return view('invoices.edit', compact('invoice')); } public function update(Request $request, Invoice $invoice): RedirectResponse { $this->authorize('update',$invoice); $invoice->update($request->validate(['status'=>'required|in:draft,sent,paid,void','notes'=>'nullable|string'])); return back()->with('status','Invoice updated.'); } public function destroy(Invoice $invoice): RedirectResponse { $this->authorize('delete',$invoice); $invoice->delete(); return redirect()->route('invoices.index')->with('status','Invoice deleted.'); } public function markSent(Invoice $invoice): RedirectResponse { $this->authorize('update',$invoice); $invoice->update(['status'=>'sent']); return back()->with('status','Invoice marked as sent.'); } }
